23. 
24.         /// <summary>
25.         /// Gets or sets Azure cloud environment.
26.         /// </summary>
27.         public ArmEnvironment? Environment { get; set; }
28. 
29.         /// <summary>
30.         /// Sets the api version to use for a given resource type.
31.         /// To find which API Versions are available in your environment you can use the <see cref="ResourceProviderResource.Get"/> method
32.         /// for the provider namespace you are interested in.
33.         /// </summary>
34.         /// <param name="resourceType"> The resource type to set the version for. To determine the appropriate value, you can refer to the corresponding documentation or XML documentation comments of the API. Then, get its resource type from the Resource's ResourceType field.</param>
35.         /// <param name="apiVersion"> The api version to use. </param>
